            int wait_tout = 50;
            while (gpio_get_level(PIN_GDO2) == 1 && wait_tout > 0) {
                vTaskDelay(pdMS_TO_TICKS(1));
                wait_tout--;
            }
            vTaskDelay(pdMS_TO_TICKS(10));
            xSemaphoreTake(carrier_sense_sem, 0); 
